```css
/* ── Dark, clean theme ── */

/* System font stack, reset body */
body {
  margin: 0;
  font-family:
    -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Fira Sans',
    'Droid Sans', 'Helvetica Neue', Arial, sans-serif;
  font-size: 14px;
  color: #e6e6e6;
  background: #1e1e1e;
}

/* Subtle accent link – used sparingly */
a {
  color: #6aa6ff;
  text-decoration: none;
}
a:hover {
  text-decoration: underline;
}

/* ── Page layout ──
   The app fills the viewport as a column so the embedded host (and therefore
   the scrollable results) gets a definite height in both views. */
html,
body {
  height: 100%;
}
#app {
  height: 100vh;
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 12px;
  box-sizing: border-box;
}

/* ── File-browser widget + hosts ──
   The widget is CHROMELESS: no border, background, or title of its own. It is
   a flex column that fills whichever host renders it (the embedded host or the
   dialog body), keeping the results area scrollable in both contexts. */
.file-browser {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
/* Embedded host: the primary, chromeless surface while the dialog is closed. */
.file-browser-host {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
/* Dialog body slot: the widget is moved here on open. Flexes to fill the
   dialog's remaining height below the titlebar. */
.browser-dialog .dialog-body {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}

/* ── Trigger button (toggle file browser) ── */
.trigger {
  padding: 8px 16px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 14px;
}
.trigger:hover {
  background: #45494d;
}

/* ── Native <dialog> styling ── */
/* Base chrome only (background/border/size/padding). Crucially we do NOT set
   `display` here: a closed <dialog> is hidden by the UA rule
   `dialog:not([open]) { display: none }`, but any author `display` declaration
   overrides the UA sheet entirely and would keep the closed dialog (and thus
   its frame/titlebar) visible on the page. The flex column layout is applied
   ONLY to the open dialog below. */
.browser-dialog {
  background: #252526;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 8px;
  /* Fixed size, clamped so it never overflows small viewports. */
  width: 960px;
  max-width: 94vw;
  height: 640px;
  max-height: 90vh;
  padding: 16px;
  /* Remove default UA margin/padding */
  margin: auto;
  box-sizing: border-box;
}
/* Flex column layout only while open, so the closed dialog stays
   `display: none` (hidden) and renders its frame only when shown. */
.browser-dialog[open] {
  display: flex;
  flex-direction: column;
}
.browser-dialog::backdrop {
  background: rgba(0, 0, 0, 0.6);
}

/* ── Header row ── */
.dialog-header {
  position: relative;
  display: flex;
  justify-content: flex-end;
  align-items: center;
  margin-bottom: 12px;
}
/* Title is absolutely centered across the full dialog width so the close
   button's width never offsets it. pointer-events:none keeps the centered
   text from intercepting clicks meant for the button. */
.dialog-header .title {
  position: absolute;
  left: 0;
  right: 0;
  text-align: center;
  margin: 0;
  font-size: 16px;
  font-weight: 600;
  pointer-events: none;
}
.dialog-header .close-btn {
  position: relative;
  z-index: 1;
  background: none;
  border: none;
  color: #9a9a9a;
  cursor: pointer;
  font-size: 20px;
  line-height: 1;
  padding: 4px 8px;
  border-radius: 4px;
}
.dialog-header .close-btn:hover {
  color: #e6e6e6;
  background: #2d2d30;
}

/* ── Toolbar ── */
.toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  margin-bottom: 12px;
}

/* Breadcrumb */
.breadcrumb {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-wrap: wrap;
}
.breadcrumb a {
  color: #9a9a9a;
  font-size: 13px;
}
.breadcrumb a:hover {
  color: #e6e6e6;
  text-decoration: none;
}

/* Search input */
.toolbar input[type='search'],
.toolbar input[type='text'] {
  background: #333337;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 4px;
  padding: 6px 10px;
  font-size: 13px;
  outline: none;
  box-sizing: border-box;
  margin-left: auto;
}
.toolbar input[type='search']::placeholder,
.toolbar input[type='text']::placeholder {
  color: #9a9a9a;
}
.toolbar input[type='search']:focus,
.toolbar input[type='text']:focus {
  border-color: #6aa6ff;
}

/* ── Results container (scrollable) ──
   Grows to fill its host's remaining height (flex: 1) and scrolls when the
   table body overflows. `min-height: 0` lets the flex item shrink below its
   content so the scrollbar engages. The table header is made sticky below, so
   only the body rows scroll. */
.results {
  flex: 1;
  min-height: 0;
  overflow: auto;
  border: 1px solid #3c3c3c;
  border-radius: 4px;
}

/* ── Table ── */
.results-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: auto;
}
.results-table th,
.results-table td {
  padding: 6px 8px;
  text-align: left;
  white-space: nowrap;
}
.results-table th {
  color: #9a9a9a;
  font-weight: 500;
  position: sticky;
  top: 0;
  background: #252526;
  z-index: 1;
  border-bottom: 1px solid #3c3c3c;
}
.results-table tbody tr:hover {
  background: #2d2d30;
}

/* ── Small action buttons ── */
.btn {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 12px;
  line-height: 1.4;
  white-space: nowrap;
}
.btn:hover {
  background: #45494d;
}
.btn:disabled {
  opacity: 0.5;
  cursor: default;
}
.btn:disabled:hover {
  background: #3a3d41;
}

/* ── Upload control accessibility ──
   The Upload file input is visually hidden with the sr-only clip pattern so it
   stays in the tab order and is keyboard-focusable (WCAG 2.1.1) — using the
   `hidden` attribute (UA display:none) instead would eject it from the focus
   order. The wrapping <label class="btn"> remains the visible affordance; the
   clipped input's own focus outline is invisible, so :focus-within reflects
   focus onto the label for sighted keyboard users. */
.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}
.toolbar label.btn:focus-within {
  outline: 2px solid #6aa6ff;
  outline-offset: 2px;
}

/* ── Status footer ── */
.status {
  margin-top: 8px;
  color: #9a9a9a;
  font-size: 12px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

