## Overall task (the goal this scouting supports)
Move the 'actions' buttons on each row into a drop-down menu that appears below the new menu button (three vertical dots should be visible on the currently hovered row, else be hidden. No border/background, muted foreground, hover on the button: foreground color change from muted to normal). The columns should adjust for this: File name becomes 'flex: 1'-like (stretch). File size and modified datetime and the actions columns should be aligned-right. The actions column doesn't need a header now (3 vertical dots on the rows is enough). Whenever the user right-clicks on the file/folder row, the SAME menu should appear as the context menu.

## Your scouting topic (stay focused here — other scouts are covering the rest)
Topic: Table headers, column layout & action-button styling
Rationale: The task requires removing the 'Actions' column header, making the Name column behave like flex:1/stretch, right-aligning Size, Modified, and Actions columns, and styling the three-dot trigger as borderless/backgroundless with a muted foreground that brightens on hover and only appears on the hovered row. render-browse.ts owns the buildTable header list; app.css owns the .results-table th/td alignment, hover rules, and .btn styling that must change.
Key files to start from: src/app/render-browse.ts, src/app.css, src/app.css.test.ts

Provide a detailed report of your findings. For each finding, briefly note how it is relevant to the overall task. Do not duplicate work that falls outside your topic.

/**
 * Pure DOM-construction helpers for the file-browser tables, breadcrumb, and
 * action controls.
 *
 * Every function here builds and returns a DOM subtree (or, for
 * `renderBreadcrumb`, populates the shared breadcrumb element from the
 * context). They hold no state of their own; the shared element refs and API
 * client are read from `./context.js`.
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 */
import type { FileEntry } from '../api.js';
import { formatBytes, formatDate, joinPath, normalizeRelativePath } from '../format.js';
import { navigate, toBrowseHash } from '../router.js';
import { getApi, getBreadcrumb, getStatus, rerender } from './context.js';

/**
 * Build a `<table>` with a `<thead>` (one `<th>` per header label) and an empty
 * `<tbody>`. The caller appends rows to the `<tbody>`.
 */
export function buildTable(headers: string[]): HTMLTableElement {
  const table = document.createElement('table');
  table.className = 'results-table';
  const thead = document.createElement('thead');
  const headRow = document.createElement('tr');
  for (const label of headers) {
    const th = document.createElement('th');
    th.textContent = label;
    headRow.append(th);
  }
  thead.append(headRow);
  const tbody = document.createElement('tbody');
  table.append(thead, tbody);
  return table;
}

/**
 * Render clickable breadcrumb segments into the shared breadcrumb element: a
 * leading "Home" link (root) followed by one link per path segment, each
 * navigating to its cumulative path. Separators are plain '/' text spans.
 */
export function renderBreadcrumb(path: string): void {
  const breadcrumbEl = getBreadcrumb();
  breadcrumbEl.innerHTML = '';
  const normalized = normalizeRelativePath(path);
  const segments = normalized === '' ? [] : normalized.split('/');

  breadcrumbEl.append(makeNavLink('Home', toBrowseHash('')));

  let cumulative = '';
  for (const segment of segments) {
    cumulative = joinPath(cumulative, segment);
    const separator = document.createElement('span');
    separator.textContent = '/';
    breadcrumbEl.append(separator, makeNavLink(segment, toBrowseHash(cumulative)));
  }
}

/**
 * Build an `<a>` that navigates to `hash` on click. The `href` is set via
 * `setAttribute` (so the raw attribute is preserved exactly — important for
 * download URLs that must not be URL-normalized) and a click handler calls
 * `navigate(hash)` with `preventDefault` so navigation is reliable across DOM
 * implementations. The href also enables middle-click / copy-link support.
 */
export function makeNavLink(text: string, hash: string): HTMLAnchorElement {
  const link = document.createElement('a');
  link.setAttribute('href', hash);
  link.textContent = text;
  link.addEventListener('click', (event) => {
    event.preventDefault();
    navigate(hash);
  });
  return link;
}

/** The ".." parent row: a Name cell whose link navigates to the parent path. */
export function makeParentRow(parent: string): HTMLTableRowElement {
  const row = document.createElement('tr');
  const nameCell = document.createElement('td');
  nameCell.append(makeNavLink('..', toBrowseHash(parent)));
  const sizeCell = document.createElement('td');
  const modifiedCell = document.createElement('td');
  const actionsCell = document.createElement('td');
  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/** One data row in the browse table (a file or folder entry). */
export function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directory names are navigation links; file names are plain text.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    nameCell.textContent = entry.name;
  }

  // Size — em-dash for folders, formatted bytes for files.
  const sizeCell = document.createElement('td');
  sizeCell.textContent = entry.isDirectory ? '—' : formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  // Actions
  const actionsCell = document.createElement('td');
  if (!entry.isDirectory) {
    const download = document.createElement('a');
    download.className = 'btn';
    download.setAttribute('href', getApi().downloadUrl(entry.path));
    download.setAttribute('download', entry.name);
    download.textContent = 'Download';
    actionsCell.append(download);
  }
  actionsCell.append(
    makeActionButton('Delete', async () => {
      if (!window.confirm('Delete "' + entry.name + '"?')) {
        return;
      }
      await getApi().delete(entry.path);
      rerender();
    }),
  );
  actionsCell.append(
    makeActionButton('Move', async () => {
      const dest = window.prompt('Move to relative destination path:', entry.path);
      if (dest === null) {
        return;
      }
      await getApi().move(entry.path, normalizeRelativePath(dest));
      rerender();
    }),
  );
  actionsCell.append(
    makeActionButton('Copy', async () => {
      const dest = window.prompt('Copy to relative destination path:', entry.path);
      if (dest === null) {
        return;
      }
      await getApi().copy(entry.path, normalizeRelativePath(dest));
      rerender();
    }),
  );

  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/**
 * Build a `<button class="btn">` with the given label and click handler.
 *
 * The handler is wrapped so that any synchronous throw or promise rejection
 * surfaces the error via the status footer — consistent with how `render()`
 * already displays fetch errors. On normal resolution no error message is
 * shown.
 */
export function makeActionButton(label: string, handler: () => void): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  btn.textContent = label;
  btn.addEventListener('click', () => {
    try {
      Promise.resolve(handler()).catch((err: unknown) => {
        getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
      });
    } catch (err) {
      getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
    }
  });
  return btn;
}

/** One data row in the search-results table. */
export function makeSearchRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directories browse into; files open their download URL.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    const link = document.createElement('a');
    link.setAttribute('href', getApi().downloadUrl(entry.path));
    link.textContent = entry.name;
    nameCell.append(link);
  }

  // Path
  const pathCell = document.createElement('td');
  pathCell.textContent = entry.path;

  // Size
  const sizeCell = document.createElement('td');
  sizeCell.textContent = formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  row.append(nameCell, pathCell, sizeCell, modifiedCell);
  return row;
}

/**
 * Render a {@link BrowseResult} into the shared results/breadcrumb/status
 * elements: a four-column table (Name | Size | Modified | Actions) with an
 * optional leading ".." parent row.
 *
 * Operates against the DOM context established by `startApp` (via
 * `render-orchestrator.init`), so it always targets the most recently mounted
 * app.
 */
import type { BrowseResult } from '../api.js';
import { formatBytes } from '../format.js';
import { buildTable, makeBrowseRow, makeParentRow, renderBreadcrumb } from './dom-builders.js';
import { getResults, getStatus } from './context.js';

export function renderBrowse(result: BrowseResult): void {
  // Breadcrumb (clickable cumulative-path segments)
  renderBreadcrumb(result.path);

  // Status footer: "N folders, M files, total S"
  getStatus().textContent =
    result.folderCount +
    ' folders, ' +
    result.fileCount +
    ' files, total ' +
    formatBytes(result.totalSize);

  // Results table
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Size', 'Modified', 'Actions']);
  const tbody = table.querySelector('tbody')!;

  if (result.parent !== null) {
    tbody.append(makeParentRow(result.parent));
  }
  for (const entry of result.entries) {
    tbody.append(makeBrowseRow(entry));
  }

  resultsEl.append(table);
}

/* ── Dark, clean theme ── */

/* System font stack, reset body */
body {
  margin: 0;
  font-family:
    -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Fira Sans',
    'Droid Sans', 'Helvetica Neue', Arial, sans-serif;
  font-size: 14px;
  color: #e6e6e6;
  background: #1e1e1e;
}

/* Subtle accent link – used sparingly */
a {
  color: #6aa6ff;
  text-decoration: none;
}
a:hover {
  text-decoration: underline;
}

/* ── Page layout ──
   The app fills the viewport as a column so the embedded host (and therefore
   the scrollable results) gets a definite height in both views. */
html,
body {
  height: 100%;
}
#app {
  height: 100vh;
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 12px;
  box-sizing: border-box;
}

/* ── File-browser widget + hosts ──
   The widget is CHROMELESS: no border, background, or title of its own. It is
   a flex column that fills whichever host renders it (the embedded host or the
   dialog body), keeping the results area scrollable in both contexts. */
.file-browser {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
/* Embedded host: the primary, chromeless surface while the dialog is closed. */
.file-browser-host {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
/* Dialog body slot: the widget is moved here on open. Flexes to fill the
   dialog's remaining height below the titlebar. */
.browser-dialog .dialog-body {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}

/* ── Trigger button (toggle file browser) ── */
.trigger {
  padding: 8px 16px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 14px;
}
.trigger:hover {
  background: #45494d;
}

/* ── Native <dialog> styling ── */
/* Base chrome only (background/border/size/padding). Crucially we do NOT set
   `display` here: a closed <dialog> is hidden by the UA rule
   `dialog:not([open]) { display: none }`, but any author `display` declaration
   overrides the UA sheet entirely and would keep the closed dialog (and thus
   its frame/titlebar) visible on the page. The flex column layout is applied
   ONLY to the open dialog below. */
.browser-dialog {
  background: #252526;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 8px;
  /* Fixed size, clamped so it never overflows small viewports. */
  width: 960px;
  max-width: 94vw;
  height: 640px;
  max-height: 90vh;
  padding: 16px;
  /* Remove default UA margin/padding */
  margin: auto;
  box-sizing: border-box;
}
/* Flex column layout only while open, so the closed dialog stays
   `display: none` (hidden) and renders its frame only when shown. */
.browser-dialog[open] {
  display: flex;
  flex-direction: column;
}
.browser-dialog::backdrop {
  background: rgba(0, 0, 0, 0.6);
}

/* ── Header row ── */
.dialog-header {
  position: relative;
  display: flex;
  justify-content: flex-end;
  align-items: center;
  margin-bottom: 12px;
}
/* Title is absolutely centered across the full dialog width so the close
   button's width never offsets it. pointer-events:none keeps the centered
   text from intercepting clicks meant for the button. */
.dialog-header .title {
  position: absolute;
  left: 0;
  right: 0;
